#include <bits/stdc++.h>
using namespace std;
int main(){
    int n,b;
    cin>>n>>b;
    int a[101]{0};
    a[0]=1;
    a[1]=1;
    for(int i=2;i<=100;i++){
        if(a[i]!=1){
            int c=2;
            a[i]=0;
            while(i*c<=100){
                a[i*c]=1;
                c++;
            }
        }
    }
    for(int i=n;i<=b;i++){
    	int d=i%10;
    	d=d*10;
    	d+=i/10;
        if(a[i]==0&&a[d]==0){
            cout<<i<<endl;
        }
    }
    return 0;
}
